<script lang="ts">import{expansionFeature,searchFeature}from'@fex/components-core';import{createTreeController}from'@fex/components-core/tree/create-tree-controller';import type{SearchFeatureApi}from'@fex/components-core/tree/features/search';import Input from'@fex/components-svelte/primitive/input';import Card from'@fex/components-svelte/ui/card';import DemoTree from'./demo-tree.svelte';import{departmentFieldNames,departmentTreeData,type DepartmentNode}from'./data';const controller=createTreeController<DepartmentNode>({treeData:departmentTreeData,fieldNames:departmentFieldNames,isLeaf:n=>n.childCount===0,features:[expansionFeature({defaultExpandedKeys:['company','engineering','product']}),searchFeature()]});let keyword=$state('');const subtree=$derived(controller.getFeature<SearchFeatureApi<DepartmentNode>>('search')?.getSubtree({keyword,filterTreeNode:(n,v)=>n.name.toLowerCase().includes(v.toLowerCase())})??[]);const showing=$derived(Boolean(keyword.trim()));function parts(title:string){const index=title.toLowerCase().indexOf(keyword.toLowerCase());return index<0?{before:title,match:'',after:''}:{before:title.slice(0,index),match:title.slice(index,index+keyword.length),after:title.slice(index+keyword.length)}}</script><Card title="Search data and custom title rendering" description="The core returns filtered tree data; title rendering decides how a keyword is highlighted."><Input value={keyword} oninput={event=>keyword=event.currentTarget.value} placeholder="Search departments" class="mb-space-md max-w-sm"/><div hidden={showing}><DemoTree {controller} treeData={departmentTreeData} fieldNames={departmentFieldNames} isLeaf={n=>n.childCount===0} features={[expansionFeature({defaultExpandedKeys:['company','engineering','product']})]} class="max-w-xl rounded-md border border-border bg-background p-space-sm"/></div>{#if showing}<DemoTree treeData={subtree} fieldNames={departmentFieldNames} isLeaf={n=>n.childCount===0} features={[expansionFeature({defaultExpandedKeys:['company','engineering','product']})]} searchKeyword={keyword} class="max-w-xl rounded-md border border-border bg-background p-space-sm">{#snippet title({item})}{parts(item.node.name).before}<mark class="rounded-sm bg-warning/20 px-0.5 text-inherit">{parts(item.node.name).match}</mark>{parts(item.node.name).after}{/snippet}</DemoTree>{/if}</Card>
